const baseUrl = '{{SUPABASE_URL}}';
const serviceKey = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': serviceKey,
  'Authorization': 'Bearer ' + serviceKey,
  'Content-Type': 'application/json'
};

const now = new Date();
const weekAgo = new Date(now - 7 * 86400000).toISOString().split('T')[0];
const todayStr = now.toISOString().split('T')[0];

// 1. Reviews this week
let weekReviews = [];
try {
  weekReviews = await helpers.httpRequest({
    method: 'GET',
    url: baseUrl + '/rest/v1/reviews?fetched_at=gte.' + weekAgo + '&select=*,member_businesses(name)&order=rating.asc',
    headers: pgHeaders
  });
} catch(e) { weekReviews = []; }

// 2. Posts this week
let weekPosts = [];
try {
  weekPosts = await helpers.httpRequest({
    method: 'GET',
    url: baseUrl + '/rest/v1/scheduled_posts?created_at=gte.' + weekAgo + '&select=*&order=created_at.desc',
    headers: pgHeaders
  });
} catch(e) { weekPosts = []; }

// 3. Tasks completed this week
let completedTasks = [];
try {
  completedTasks = await helpers.httpRequest({
    method: 'GET',
    url: baseUrl + '/rest/v1/tasks?status=eq.done&completed_at=gte.' + weekAgo + '&select=title,completed_at,priority',
    headers: pgHeaders
  });
} catch(e) { completedTasks = []; }

// 4. Still pending tasks
let pendingTasks = [];
try {
  pendingTasks = await helpers.httpRequest({
    method: 'GET',
    url: baseUrl + '/rest/v1/tasks?status=in.(pending,in_progress)&parent_id=is.null&select=title,priority,due_date,status',
    headers: pgHeaders
  });
} catch(e) { pendingTasks = []; }

// Build report
const weekStart = new Date(now - 6 * 86400000).toLocaleDateString('de-DE', {day:'numeric', month:'long', timeZone:'Europe/Berlin'});
const weekEnd = now.toLocaleDateString('de-DE', {day:'numeric', month:'long', year:'numeric', timeZone:'Europe/Berlin'});

let report = '# 📊 Wochenbericht — ' + weekStart + ' bis ' + weekEnd + '\n\n';

// Reviews summary
report += '## ⭐ Bewertungen\n';
if (weekReviews.length > 0) {
  const avgRating = (weekReviews.reduce((s,r) => s + r.rating, 0) / weekReviews.length).toFixed(1);
  const ratingDist = [1,2,3,4,5].map(r => weekReviews.filter(rv => rv.rating === r).length);
  report += weekReviews.length + ' neue Bewertungen, Durchschnitt: ' + avgRating + '★\n';
  report += 'Verteilung: ★' + ratingDist.join(' | ★') + '\n';
  const unanswered = weekReviews.filter(r => !r.answered);
  if (unanswered.length > 0) report += '⚠️ ' + unanswered.length + ' unbeantwortete Bewertung(en)\n';
  // Top businesses
  const bizCounts = {};
  weekReviews.forEach(r => { const n = r.member_businesses?.name || 'Unbekannt'; bizCounts[n] = (bizCounts[n] || 0) + 1; });
  report += 'Nach Betrieb: ' + Object.entries(bizCounts).map(([n,c]) => n + ' (' + c + ')').join(', ') + '\n';
} else {
  report += 'Keine neuen Bewertungen diese Woche.\n';
}
report += '\n';

// Posts summary
report += '## 📱 Social Media\n';
if (weekPosts.length > 0) {
  const published = weekPosts.filter(p => p.status === 'published');
  const failed = weekPosts.filter(p => p.status === 'failed');
  const pending = weekPosts.filter(p => p.status === 'pending');
  report += published.length + ' veröffentlicht';
  if (failed.length > 0) report += ', ' + failed.length + ' fehlgeschlagen';
  if (pending.length > 0) report += ', ' + pending.length + ' ausstehend';
  report += '\n';
} else {
  report += 'Keine Posts diese Woche.\n';
}
report += '\n';

// Tasks summary
report += '## ✅ Aufgaben\n';
report += completedTasks.length + ' erledigt, ' + pendingTasks.length + ' noch offen\n';
if (pendingTasks.length > 0) {
  const urgent = pendingTasks.filter(t => t.priority === 'urgent' || t.priority === 'high');
  if (urgent.length > 0) {
    report += '⚠️ ' + urgent.length + ' dringende Aufgaben:\n';
    urgent.forEach(t => {
      const due = t.due_date ? ' (fällig: ' + new Date(t.due_date).toLocaleDateString('de-DE', {timeZone:'Europe/Berlin'}) + ')' : '';
      report += '- ' + t.title + due + '\n';
    });
  }
}
report += '\n';

// Save report to DB
try {
  await helpers.httpRequest({
    method: 'POST',
    url: baseUrl + '/rest/v1/memory_daily',
    headers: { ...pgHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      date: todayStr,
      content: report,
      role: 'weekly_report',
      user_id: 'system'
    })
  });
} catch(e) {}

return [{ json: { report, date: todayStr } }];
